1	4	{"plan_name": "8‑Week Beginner Weight‑Loss Muscle Builder", "primary_goal": "weight_loss", "duration_weeks": 8, "weekly_schedule": {"day1": {"focus": "Strength", "day_name": "Monday", "exercises": [{"reps": "10-12", "sets": 3, "exercise": "Dips (Chest focus)", "rest_sec": 60, "image_url": "https://burnfit.io/wp-content/uploads/2023/11/DIPS.gif", "instructions": ["Safety: Keep shoulders down and avoid excessive depth to protect the shoulder joint.", "Performance: Press up until arms are nearly straight, then lower with control.", "Benefits: Develops chest thickness and engages triceps."], "target_muscle": "Chest", "calories_burned": 17}, {"reps": "10-12", "sets": 3, "exercise": "Floor Press", "rest_sec": 60, "image_url": "https://burnfit.io/wp-content/uploads/2023/11/BB_FLOOR_PRESS.gif", "instructions": ["Safety: Keep shoulders retracted and back flat on the floor.", "Performance: Press the dumbbells upward until arms are fully extended, then lower with control.", "Benefits: Builds chest, shoulder, and triceps strength."], "target_muscle": "Chest", "calories_burned": 18}, {"reps": "10-12", "sets": 3, "exercise": "Cable Crossover", "rest_sec": 60, "image_url": "https://burnfit.io/wp-content/uploads/2023/11/CROSS_OVER.gif", "instructions": ["Safety: Adjust the pulleys to shoulder height and keep a slight bend in the elbows.", "Performance: Bring the handles together in front of the chest, squeezing at the peak.", "Benefits: Isolates the pectoral muscles for shape and definition."], "target_muscle": "Chest", "calories_burned": 18}, {"reps": "10-12", "sets": 3, "exercise": "Close-grip Push Up", "rest_sec": 60, "image_url": "https://burnfit.io/wp-content/uploads/2023/11/CG_PUSH_UP.gif", "instructions": ["Safety: Keep the body in a straight line and hands directly under the chest.", "Performance: Lower until elbows are at about 45°, then push back up.", "Benefits: Emphasizes triceps while still recruiting the chest."], "target_muscle": "Chest", "calories_burned": 18}, 